import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    pkgs = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b, a = get_pkgs(baseline), get_pkgs(after)
changes = {k: (b[k], a[k]) for k in b if b.get(k) != a.get(k)}
missing = {k: b[k] for k in b if k not in a}
added = {k: a[k] for k in a if k not in b}
if not changes and not missing and not added:
    print('All packages resolve identically to baseline.')
else:
    for k,(bv,av) in changes.items(): print(f'CHANGED: {k} {bv} -> {av}')
    for k,v in missing.items(): print(f'REMOVED: {k} {v}')
    for k,v in added.items(): print(f'ADDED: {k} {v}')
"

